import java.util.*;

public List<String> excelSheetCells(String s) {
    int r1, r2;
    char c1, c2;

    String[] parts = s.split("[:]");
    c1 = parts[0].charAt(0);
    r1 = Integer.parseInt(parts[0].substring(1));
    c2 = parts[1].charAt(0);
    r2 = Integer.parseInt(parts[1].substring(1));

    List<String> result = new ArrayList<>();

    for (char c = c1; c <= c2; c++) {
        for (int r = r1; r <= r2; r++) {
            result.add(String.valueOf(c) + r);
        }
    }
    return result;
}
```

